        SayNode(character: "ar", dialogue: "「但不是《无限的循环日常：不存在的存在悖论》。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "我的脸一下子就红了……", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "不是因为没有玩过《终结的循环日常》。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "恰恰，是玩过了《终结的循环日常》，也玩过《无限的循环日常：不存在的存在悖论》。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "这是一个横跨数十年的系列，《终结的循环日常》和《无限的循环日常：不存在的存在悖论》。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "言上彩黑作为横跨两部作品的共同角色，在每一作中都有着类似却又不同的定位。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "这两部作品是同一个作者在不同时期不同心境的产物，其中《终结的循环日常》是一切的源头，而《无限的循环日常：不存在的存在悖论》则是在这之上更加“普世”的迭代，理所应当地拥有更高的人气和知名度。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "但是和人气无关，也和我的喜好无关。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "我只是——", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「你就是觉得鸦露露没玩过你玩过的游戏吧？」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「……」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
