        SayNode(character: "ar", dialogue: "「哼，你刚才肯定想过，“这个人肯定没有玩过多少电波作吧？”」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「就因为鸦露露最先提到的是彼女彼女！」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「再说，《终结的循环日常》本身也没有多小众吧！和《霁》难道不是一个级别的吗？」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「我……我喜欢《无限的循环日常：不存在的存在悖论》不可以吗？」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
