        SayNode(character: null, dialogue: "我喜欢看别人的想法，也喜欢讨论游戏，但不知道为什么，唯独对解说GALGAME视频的态度不一样。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
