        SayNode(character: null, dialogue: "抱着日语学习，和至少放在耳边的内容喜欢的东西的心情，", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "我打开了视频，内心驱动自己同时做起别的事。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "尽管现在几乎什么都可以在电脑上完成了，但唯独确认思路的时候我只能在纸面上进行。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "继续进行着意味不明字符创作，将这一点和那一点连在一起，好像弄白了什么！", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "但是因为没有进行彻底的语言化，所以内心的想法还是暧昧不明地像是糨糊。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q2c", dialogue: "「？？：……简单来说，这是一款淋漓尽致表现暴力与被暴力的游戏。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "玩家可以选择体验施暴的视角，也可以体验被施暴的视角……就是这样带有恶趣味性质的，在游戏制作之初就存在的玩家用户画像，或者说是为了拓展受众面的经营理念。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "笨拙的日语水平只支持我在神游的时候捕捉到一些关键词，", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "但是仅凭这些关键词我就能轻易连接起她想表达的意思。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "理由很简单，因为，这些话就好像是从我脑中摘出的话。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3c", dialogue: "「？？？：但是！如果从路线分布来看，意外的是个某种意义上来说“温暖人心“的故事哦！？」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3c", dialogue: "「？？？：首先，如果按照玩家的一般常识来看，除去一个陷阱之外，没有任何进入重口味结局的可能性。也就是说，实际上这个游戏的重口味发展可以说是这个游戏的隐藏内容！」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3c", dialogue: "「？？？：如果一开始没有中那个陷阱的话，甚至可以一路进入像是梦一样的HE，但是如果本身就是重口内容的爱好者，则可以和一般思维反其道而行，去享受自己想要的游戏体验。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3c", dialogue: "「？？？：不过，刚才也说了。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3c", dialogue: "「？？？：其中有一个陷阱。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "我放下了手中的笔，咽了口口水。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "画面上的出现的是身着地雷服的女生——应该说是虚拟形象。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "原来还有在做猎奇致郁Galgame解说的虚拟主播吗。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "但总觉得，有些熟悉。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "夹杂在她话语之间的瞬间思考，在她说出下一句话的一瞬，注意力就已经再次转移到她所说的话上了。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3c", dialogue: "「？？？：这个陷阱由两个选项组成，其中第一个选项，是在女主A将女主B监禁之后，否要逃，第二个选项则是在女主A使用刀片攻击的时候是否要反抗。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3c", dialogue: "「？？？：这两个选项看上去共用同一种逻辑，然而实际上只要按照同一个逻辑去理解，就一定会走向错误结局。唯独这一点，和玩家接受的一般常识不同——也就是说，一个反GALGAME常识的陷阱。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3c", dialogue: "「？？？：说不定这个视频也有不怎么玩GALGAME的人在看！所以就由我来简单讲解一下所谓的GALGAME常识吧！一般来说，GALGAME非常看重逻辑的一贯性，比如A逻辑，完全对应A角色，如果所有选项全都对应A逻辑，那么基本可以确定能够走进A角色的最好结局，而这个A角色对应的A逻辑究竟是什么，基本会在玩家试错的环节中慢慢让玩家知晓，当然最近的游戏，选项普遍简单，或许我们马上就要失去这种尝试了呢，呵呵…」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3c", dialogue: "「？？？：所以说，现在明白了吗？」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "《有爱百合消失之日》的陷阱就在于，当女主B被监禁后，如果趁乱逃离则会被抓住后，被施以更糟糕的对待方式。然而当玩家习得了这一逻辑时，学会了需要一定程度上顺从女主A的玩家们，却面临了背叛。——此时需要抓住双面的刀片，将原本被女主A刺到胸口的刀片推回女主A的胸前。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3c", dialogue: "「？？？：当然，这样的角色逻辑仍然有一贯性，简单来说，在这部作品中，就是【1.具有自我地 2.对女主2一心一意】，但是要悟透这一点，几乎必须等你打破了之前错以为的一贯的逻辑之后，才能够发现。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "她说完这段长句，我才好像突然从异世界抽离，意识到自己已经很久没有动作了，从刚才起就一直僵在了原地。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "这个思路……", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "像是打开了一台收音机，发现里面放的竟全是自己的心声！", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "q3c", dialogue: "「？？？：《无限■亡少女之歌》也是一样的！」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "——（我）：没错。《无限■亡少女之歌》的主线其实是一个反抗故事！", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
