        SayNode(character: null, dialogue: "【选项：天台】", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "前往天台。前往天台。前往天台。前往天台。前往天……", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "少女背对着我，与上次不同，天色正早，日光洒在她身上，灼烧着我的眼睛。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "找到了。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "彻夜不眠导致的心跳声，随着阳光也照射到我身上，与往常的烦躁不同，此刻正仿佛温和地将我包裹。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "奇妙的感觉。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "只能用出这样的词。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "我轻声靠近她，想着要走到哪一步才应该让她发现，内心无限向后拖延着被她发现的时间。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "并不是讨厌被她发现，恰恰相反，是害怕不能在“最好”的时机向她说出第一句话。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "那么，要说什么才好呢？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "和她的第一句话。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "好久不见？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
