        SayNode(character: null, dialogue: "不成声的话语，我已站到了她的身侧，哪怕我不说话，也理应被她发现了，然而她一动不动，是无视了我……吗？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "但看起来不像，她只是看着远处。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "她的侧脸，看上去比我记忆中的要冰冷至少十分，甚至不像是我印象中的她。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
