        SayNode(character: null, dialogue: "在我自己还没有意识到的时候，我已经在距离她半米的地方，和她摆起了一样的姿势。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "明明在想着她的事，却只是看着眼前的高楼、上班族、女子高中生，好像在俯视世上的一切，又好像被从世界中剥离。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "不会与这个世界相连，但也不会被其他的世界召唤，明明是白天，但正是因为白天，被这个世界所抛弃的感受就分外强烈。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "再这样下去就算哭起来也不奇怪。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "但是，一下子明白了。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
