        SayNode(character: "me", dialogue: "「不是说，“好女人就是要有距离天空最近的距离，还有蕾丝吗？”」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
