        SayNode(character: null, dialogue: "难道不是所有玩过《无限的循环日常：不存在的存在悖论》的人都能理解的句子吗！", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
