        SayNode(character: null, dialogue: "可是按照刚才的流势，如果我提到香烟的话，感觉就会立刻生成一支香烟在我面前。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
