        SayNode(character: "ar", dialogue: "「呜啊，好难听的说法！嗯，这个因人而异不是吗？因为是你，所以这不是筛选。毕竟，鸦露露相信你和鸦露露肯定会再见面的。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「只不过，鸦露露想对一下答案。所以这个过程是必须的！」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「只是把话说得好听了一些而已吧！」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「相信我嘛！」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "她的眼睛就在我的面前，我们之间没有间隔任何东西，感到有些前所未有的紧张，或许也掺杂着些许害怕，但是，这种感觉却很温柔。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
