        SayNode(character: null, dialogue: "难道世界就是这样的构造吗？就算没有触碰到，只要距离够近就能够感受到她人的体温。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
