        SayNode(character: null, dialogue: "但是，此刻，我或许是感受到了她的体温。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "就在这样的温度中，我败下阵来，承认了她说的话。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
