        SayNode(character: null, dialogue: "就算是筛选也好，通过了筛选的我已经不需要担心其他的事了。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "不知道是不是收到睡眠不足的影响，一向以负面想法为主的我居然也有这样无法感知到负面情绪的一天。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "就像是在和自己对话似的安心感，回过神的时候，已经将自己的游戏历全都讲了一遍。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "意外的是，我玩过的游戏她居然也都玩过！", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "虽然我有想过会重合，但是到这种地步我也很难想象！", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "肯定也有只有我玩过，或是只有她玩过的游戏吧。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "那些是我玩过却不那么感兴趣的游戏，所以无法第一时间想起。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "但如果只是这些游戏有所不同，那这和我们玩过的游戏完全一致又有什么区别呢？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「不过啊，你的蕾丝呢？」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
