        SayNode(character: null, dialogue: "我看她将《不会被言秋察觉的交往法》拿在手上，随手翻了翻。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
