        SayNode(character: null, dialogue: "我手上的三本书，一本是作为交换的漫画，另一本也是作为交换的书《不会被言秋察觉的交往法》，最后一本则是趁她不备偷偷买下的《哥特文化全囊括》。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
