        SayNode(character: null, dialogue: "我们蹲在地上看着来往的行人，而如今也已经没有对我们感到好奇的路人了。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
