        SayNode(character: null, dialogue: "宿新的速度很快，不管发生什么都像是过眼云烟，尤其是对于他人的事——我很忙，最好不要让我也卷入麻烦——这好像是人们的共识。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "虽说宿新大概也有完全相反的地方，但那些地方难道不也是贯彻了同样的想法的不同表象而已吗？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "想着这样的事，突然意识到，在研究室进行汇报，到书店，然后是中古店，甚至是逃生，这些竟然全都是今天一天之内的事。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "忍不住感慨。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
