        SayNode(character: "ar", dialogue: "「嗯……都说快乐的时间是短暂的，也就是说……」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「STOP！NONO！是、是感觉很充实！」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
