        SayNode(character: null, dialogue: "像是这样的现充动画电影，至今为止我应该没看过任何一部。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "但总觉得，这次并不抗拒。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
