        SayNode(character: null, dialogue: "她走在前，捧着爆米花却好像按捺不住内心的期待，小小地跳着向前走。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
