        SayNode(character: null, dialogue: "正当我漫无目的胡思乱想的时候，我意识到身旁的人异常的安静。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
