        SayNode(character: "ar", dialogue: "「这其实是个创作的故事吧？」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「啊！！不愧是你！没错！我也这么觉得！关键主线的节点变化全都依靠创作的状态，重要的创作物的完成程度来隐喻展现！然后这个重要的创作物则成为了关键道具，可惜的是到结尾反而不再提到了……啊，不过这也很平常吗，只是因为感动到我了所以才会给出高评价吗……」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "偶尔，亢奋地说出某个观点后，会突然进入客观视角，热情冷却之后……连自己也不赞同自己的观点了。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「不！你说得对！创作即是心！创作的表现就是心的表现！而且，多亏了创作，才将主角如何面对过去的创伤展现得一清二楚，并且将所有伏笔全都完美地回收了！没错！不仅仅是将厉害的部分展现给观众，不能一味地膨胀观众的期待，尤其是现在非常流行的“将问题扔给甚至不知道存不存在的第二季”，而是要将期待全都回收才对啊！」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「嗯！！！！！！」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
