        SayNode(character: null, dialogue: "是因为照顾到我的心情吗，所以一直送我到地铁站。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "确实，之前的恐惧已经全都被对电影的感想填满。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
