        SayNode(character: null, dialogue: "难道说，留下一半的感想不能和她交谈，以此来削减我的害怕，就是她原本的设想吗？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
