        SayNode(character: "ar", dialogue: "「这次，好像轮到鸦露露有些害怕了……」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「诶？！」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "怎么会这样，为了我去看了电影所以拖延了时间，反而导致她内心的恐惧开始蔓延生长了吗……？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
