        SayNode(character: null, dialogue: "好像已经不是第一次了。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "发去消息后，我去浴室洗了个澡，回来之后很快在LINA上收到了她的回信。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "【安全到达！HE！】", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "笨蛋。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "突然，我意识到了两件事。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "其一，不仅书的钱大多都被她付走了。就连看电影的钱也是她付的……可恶，当时注意力完全在其他事情上了。不行啊我这样！总有一天我要改掉“只能专注一件事”的怀毛病！真是拜了自己是笨蛋所赐，欠了她好多……", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "其二，她没有进闸口。那个车站意外地能通向各个路线，也就是说，她住在能够步行到达的地方吗？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "不，我不是跟踪狂！", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "我打开笔记本。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "应该继续写论文了……", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "写下关于她的事", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "写下关于电波奇作的事", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "写下了对她的记录。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "抱有歉意的……", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "说到底，要对人进行评价本身就很不尊重人了！", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "但是，但是……如果没有的话……我就只能放弃了。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "这些终究都只是借口吗。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "必须要抱着罪恶感继续……这才是最底线的尊重。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "虽然最好还是不要做这种事了！", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "不过如果一定要做的话……必须要做到能力范围的最好！", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "那么，说到底，地雷系究竟是什么呢？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "这样草率地下判断真的好吗？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "心中充斥着矛盾和困惑，就这样躺到了地上。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "失去了意识。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "写下了对三大电波奇作的记录。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "原本就是因为电波作才与她相遇的。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "今天的出行再次让我想到了更多关于三大奇作的事。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "或许我想知道的答案就藏在那些作品里？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "隐约有这种预感。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "心中充斥着困惑，就这样躺到了地上。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "失去了意识。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "夜。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "徘徊在街上。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "东京独有的，夜晚的诡异音波。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "一阵阵侵入耳膜。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "身体不由自主地行动着。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "不由自主——不是的，只是比平日更加轻盈而已。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "仿佛被从重力中释放。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "身体摇晃着。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "并非是因为没有力气。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "而是无法控制眼下的身体。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "像是——", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "漂浮在月球。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "在无法看清双手的深夜，没有任何灯光。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "只有月色流淌下的苍白，也被高耸的建筑完全吞噬。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "纯粹的黑色，在现代也仍然存在。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "尽管无法看清眼前的路，但我的目标却很清晰。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "嗅觉。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "像是黑夜中点亮的灯，想要凑近——生出这样的欲望。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "什么都不会得到，就算那样也没关系。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "只是纯粹的欲望。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "吸引着我靠近。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
