        SayNode(character: null, dialogue: "但是，我想要逃离。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "于是我向上弹起，竟然轻松地越过了高楼。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
