        SayNode(character: "me", dialogue: "「等等刚才是怎么回事！」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "……嗯……难道是，总不能是，聊天的人太多了弄混了吧。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
