        SayNode(character: null, dialogue: "……", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "一瞬间大脑被无数的可能性占满，其实我也知道，如果谈及这个话题，一定会走到这一步，所以最好的做法就是干脆自己避开这个话题。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "然而，我却对着她已经倾诉了很多，无可避免地走到这个境地。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "实际上，在过去或许我也犯过无数次这样的错误，理应我早该学到了的。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
