        SayNode(character: null, dialogue: "于是就这样轻浮地将自己不想被人知道的秘密说出了口。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "早在书店的时候就已经被她看透许多了吧……", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
