        SayNode(character: null, dialogue: "因为正在思考电波系的事，其实一直感到后背有些恐慌。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "虽然正在一板一眼的思考电波系的事，但如果我生在那个时代的话，或许就会是相信电波的一份子吧。……吗？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "她好像留下了一个微笑就离开了——其实我没看清，因为速度很快。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "我看着她的背影接近收银台，再次回来的时候她好像带了两杯饮料。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
