        SayNode(character: null, dialogue: "突然被问到，一下子丢失了刚才的记忆，想要回答她的问题，只好追溯到思维最初的地方。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「我在想，如果我出生在那个时候，这个地点的话，大概也会是相信……相信可能不太准确，应该说，是不会否认“毒电波”的存在，内心某个角落潜意识里认为“毒电波”的存在是合乎某种规则的。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
