        SayNode(character: null, dialogue: "混合在司空见惯的日常中的异物吗……", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「为什么大家会相信“毒电波”呢？」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「如果是那个时代的话，大概不只是相信“毒电波”的存在吧。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "她自然地绕过了自己的想法。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "在我犹豫要不要说穿这一点的时候，她又一次开口。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「因为在“电波”出现之前就已经抱有怀疑，感到不安。所以在电波出现之后，才会将那些怀疑和不安寄于电波身上。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「电波只是，变成了载体。变成了能够“命名”，能够确切演说的“不安”载体。客观上来说，也确实带来了更多的不安，也就是说，同时是载体，也是扩音器。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「妄想。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「如果没有在文艺作品中的赋予能力，那么电波就只是妄想。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "听起来像是在说没有超能力的文艺作品就是妄想一样的一般论了。 ", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "但她的意思，大概是想说“毒电波”与“妄想”的差异。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "如果毒电波本身不存在，那么存在本身就是妄想的“毒电波”。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "通过妄想（=创作）的赋能，在作品中成为了真正的超越性，真实存在的危险与威胁。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "妄想在妄想中变成了真实。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "要说是一般论也确实是一般论。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「实际上不是也存在“毒电波”在作品中也不过是妄想——这样的作品吗。换句话来说，也就是没有给毒电波赋予特殊能力而已。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "妄想（=创作）中的妄想。（＝现实不存在的电波系，在虚构作品中也不存在，即电波系是彻头彻尾的，不论在哪里都是，妄想。）", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "和妄想（=创作）中的现实。（＝现实不存在的电波系，在虚构作品中作为现实存在，即电波系是创作中的现实，这反而在现实中仅仅是一种妄想）", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "这两种概念是不是互相反过来说也都成立呢？", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "妄想（＝创作）中的妄想。（利用创作，在妄想中赋予另一种妄想特殊的能力，即电波是在创作中拥有超越性的东西）", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "妄想（＝创作）中的现实。（在妄想中的，却是我们熟知的现实，即电波系在创作中也仍然是不具有超越性的东西。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "正好与刚才所说的相反。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "概念就这样轻易地互相颠倒。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「仔细想想是很有意思的逻辑吧？」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「说到妄想，听说当时有很多被认为有“统合失调症”的患者都出现了这样的症状——认为毒电波存在。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「毒电波，妄想，超越性，病症……」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「接着刚才的话题，在漫画作品中获得了命名的“毒电波”，继而在漫画作品中获得了“电波系”的类别命名。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「这就是我们所知道的电波系。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「嗯。然后是鸦露露和你更熟知的话题了。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "她笑了笑，像是等待我接话。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「家用机开始普及。尤其是……GALGAME即将引来它的时代。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「没错。在同一时代，那么自然“电波系”的这一妄想，这次又会寄居在“GALGAME”这一载体中。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「你应该也想到了吧？」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「《霁》。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
