        SayNode(character: "ar", dialogue: "「没错。而要提到《霁》就不得不提到另外一部作品。虽然不是GALGAME。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「《新兴灰羽教》。一本以“毒电波”为题材的小说。直接影响到了《霁》的设定，内容方面也有着非常多的共通点。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「超越性的“神”，死亡，精神疾病，药物使用……」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "也就是和妄想有关的几乎全部。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "电波，也就是妄想……吗。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "ar", dialogue: "「之后诞生的就更是有名的三部作品了。」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: "me", dialogue: "「三大电波奇作。《终结的循环日常》《纱椰教》《少女的99种方法》……」", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        SayNode(character: null, dialogue: "说出口的瞬间，脑海中忽然想到的，居然是在这短短十几天里，与她的多次相遇。", pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
